(()=>{function h(t,o,s,d){let i=new Array(t.length),a=0,l=new Set;o.forEach((n,e)=>{n.onmessage=c=>{let r=c.data;if(!r)return;let u=Number(r.id);if(i[u]=r.result||{error:r.error},l.delete(e),a<t.length){let g=a++;l.add(e),n.postMessage({cmd:"solve",id:String(g),problem:t[g],maxDepth:s,timeLimitMs:d})}}});for(let n=0;n<o.length&&!(a>=t.length);n++){let e=a++;l.add(n),o[n].postMessage({cmd:"solve",id:String(e),problem:t[e],maxDepth:s,timeLimitMs:d})}return new Promise(n=>{let e=setInterval(()=>{i.filter(r=>r!==void 0).length===t.length&&(clearInterval(e),o.forEach(r=>r.terminate()),n(i))},50)})}window.runParallelShared=async(t,o=4,s=4,d=1e4)=>{let a=new SharedArrayBuffer(Int32Array.BYTES_PER_ELEMENT*16384*3),l=Math.min(o,t.length),n=[];for(let e=0;e<l;e++)n.push(new Worker("/worker-parallel.js"));return await Promise.all(n.map(e=>new Promise(c=>{let r=u=>{u.data&&u.data.cmd==="ready"&&(e.onmessage=null,c())};e.onmessage=r,e.postMessage({cmd:"init",sab:a,slots:16384})}))),await h(t,n,s,d)};window.runParallelIndependent=async(t,o=4,s=4,d=1e4)=>{let i=Math.min(o,t.length),a=[];for(let l=0;l<i;l++)a.push(new Worker("/worker-parallel.js"));return await h(t,a,s,d)};window.runParallel=window.runParallelShared;})();
